using System.ComponentModel;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Logging;
using OpenAI;
using ResearchAgent;

var builder = Host.CreateApplicationBuilder(args);

builder.Services.AddSingleton<Notepad>();

builder.Services.AddChatClient(chatClientBuilder => chatClientBuilder
    .UseOpenAIChatClient(
        builder.Configuration["AI:ModelId"] ?? "gpt-4o-mini-2024-07-18",
        new OpenAIClient(
            builder.Configuration["AI:ApiKey"]
                ?? Environment.GetEnvironmentVariable("OPENAI_API_KEY")
                ?? throw new InvalidOperationException(
                    "Set AI:ApiKey in config or OPENAI_API_KEY env var."))));

builder.Services.AddHostedService<ResearchWorker>();

var host = builder.Build();
await host.RunAsync();

