using System.Text;

namespace ResearchAgent;

/// <summary>
/// In-memory notepad that the agent uses to collect research findings.
/// </summary>
public sealed class Notepad
{
    private readonly List<NoteEntry> _entries = [];
    private readonly Lock _lock = new();

    public void AddNote(string title, string content)
    {
        lock (_lock)
        {
            _entries.Add(new NoteEntry(title, content, DateTime.UtcNow));
        }
    }

    public IReadOnlyList<NoteEntry> GetNotes()
    {
        lock (_lock)
        {
            return [.. _entries];
        }
    }

    public string FormatAllNotes()
    {
        lock (_lock)
        {
            if (_entries.Count == 0)
            {
                return "(no notes taken yet)";
            }

            var sb = new StringBuilder();
            for (var i = 0; i < _entries.Count; i++)
            {
                var entry = _entries[i];
                sb.AppendLine($"--- Note {i + 1}: {entry.Title} ---");
                sb.AppendLine(entry.Content);
                sb.AppendLine();
            }

            return sb.ToString();
        }
    }
}

public sealed record NoteEntry(string Title, string Content, DateTime Timestamp);

using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Logging;

namespace ResearchAgent;

/// <summary>
/// Tools exposed to the AI agent for web searching and note-taking.
/// </summary>
public sealed class ResearchTools
{
    private readonly Notepad _notepad;
    private readonly ILogger<ResearchTools> _logger;
    private readonly HttpClient _httpClient;
    private readonly string? _searchApiKey;
    private readonly string? _searchEngineId;

    public ResearchTools(
        Notepad notepad,
        ILogger<ResearchTools> logger,
        IConfiguration configuration)
    {
        _notepad = notepad;
        _logger = logger;
        _httpClient = new HttpClient();

        _searchApiKey = configuration["Search:ApiKey"]
            ?? Environment.GetEnvironmentVariable("GOOGLE_SEARCH_API_KEY");
        _searchEngineId = configuration["Search:EngineId"]
            ?? Environment.GetEnvironmentVariable("GOOGLE_SEARCH_ENGINE_ID");
    }

    [Description("Searches the web for information on a query. Returns a list of result titles, snippets, and URLs.")]
    public async Task<string> SearchWebAsync(
        [Description("The search query to look up on the web")] string query,
        [Description("Maximum number of results to return (1-10)")] int maxResults = 5)
    {
        maxResults = Math.Clamp(maxResults, 1, 10);
        _logger.LogInformation("Searching web for: {Query}", query);

        if (!string.IsNullOrEmpty(_searchApiKey) && !string.IsNullOrEmpty(_searchEngineId))
        {
            return await SearchWithGoogleAsync(query, maxResults);
        }

        _logger.LogWarning("No search API configured — using simulated results");
        return GetSimulatedResults(query);
    }

    [Description("Saves a research note with a title and content. Use this to record key findings from your research.")]
    public string SaveNote(
        [Description("A short, descriptive title for this note")] string title,
        [Description("The content of the note — key facts, quotes, or insights")] string content)
    {
        _notepad.AddNote(title, content);
        _logger.LogInformation("Note saved: {Title}", title);
        return $"Note '{title}' saved successfully. Total notes: {_notepad.GetNotes().Count}";
    }

    [Description("Retrieves all research notes taken so far.")]
    public string ReadNotes()
    {
        var notes = _notepad.FormatAllNotes();
        _logger.LogInformation("Reading {Count} notes", _notepad.GetNotes().Count);
        return notes;
    }

    private async Task<string> SearchWithGoogleAsync(string query, int maxResults)
    {
        var url = $"https://www.googleapis.com/customsearch/v1?key={_searchApiKey}"
            + $"&cx={_searchEngineId}&q={Uri.EscapeDataString(query)}&num={maxResults}";

        try
        {
            var response = await _httpClient.GetFromJsonAsync<JsonElement>(url);
            var items = response.GetProperty("items");
            var results = new List<string>();

            foreach (var item in items.EnumerateArray().Take(maxResults))
            {
                var title = item.GetProperty("title").GetString();
                var snippet = item.GetProperty("snippet").GetString();
                var link = item.GetProperty("link").GetString();
                results.Add($"Title: {title}\nSnippet: {snippet}\nURL: {link}");
            }

            return string.Join("\n\n", results);
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "Google search failed, falling back to simulated results");
            return GetSimulatedResults(query);
        }
    }

    private static string GetSimulatedResults(string query)
    {
        return $"""
            Search results for: "{query}"

            1. Title: Overview of {query} - Wikipedia
