    {
        _chatClient = chatClient;
        _tools = tools;
        _notepad = notepad;
        _lifetime = lifetime;
        _logger = logger;
    }

    protected override async Task ExecuteAsync(CancellationToken stoppingToken)
    {
        Console.WriteLine("╔═══════════════════════════════════════╗");
        Console.WriteLine("║       AI Research Agent               ║");
        Console.WriteLine("║  Enter a topic to research, or       ║");
        Console.WriteLine("║  'quit' to exit.                     ║");
        Console.WriteLine("╚═══════════════════════════════════════╝");
        Console.WriteLine();

        while (!stoppingToken.IsCancellationRequested)
        {
            Console.Write("Research topic: ");
            var topic = Console.ReadLine();

            if (string.IsNullOrWhiteSpace(topic)
                || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
            {
                break;
            }

            try
            {
                await RunResearchAsync(topic, stoppingToken);
            }
            catch (Exception ex) when (ex is not OperationCanceledException)
            {
                _logger.LogError(ex, "Research failed");
                Console.WriteLine($"\nError: {ex.Message}");
            }

            Console.WriteLine();
        }

        _lifetime.StopApplication();
    }

    private async Task RunResearchAsync(string topic, CancellationToken ct)
