using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Logging;

namespace ResearchAgent;

/// <summary>
/// Background service that prompts the user for a topic, runs the research
/// agent, and prints a summary.
/// </summary>
public sealed class ResearchWorker : BackgroundService
{
    private readonly IChatClient _chatClient;
    private readonly ResearchTools _tools;
    private readonly Notepad _notepad;
    private readonly IHostApplicationLifetime _lifetime;
    private readonly ILogger<ResearchWorker> _logger;

    private const string AgentInstructions = """
        You are a research agent. Your job is to investigate a topic thoroughly
        by searching the web and recording your findings in notes.

        Follow this process:
        1. Break the topic into 2-3 specific search queries.
        2. For each query, use the SearchWebAsync tool to find information.
        3. After each search, use the SaveNote tool to record the key findings
           with a descriptive title.
        4. After gathering enough information, use the ReadNotes tool to review
           all your notes.
        5. Finally, provide a comprehensive summary that synthesizes all your
           research notes into a coherent overview.

        Be thorough but concise. Focus on factual information and cite sources
        where possible.
        """;

    public ResearchWorker(
        IChatClient chatClient,
        ResearchTools tools,
        Notepad notepad,
        IHostApplicationLifetime lifetime,
        ILogger<ResearchWorker> logger)
    {
        _chatClient = chatClient;
        _tools = tools;
        _notepad = notepad;
        _lifetime = lifetime;
        _logger = logger;
    }

    protected override async Task ExecuteAsync(CancellationToken stoppingToken)
    {
        Console.WriteLine("╔═══════════════════════════════════════╗");
        Console.WriteLine("║       AI Research Agent               ║");
        Console.WriteLine("║  Enter a topic to research, or       ║");
        Console.WriteLine("║  'quit' to exit.                     ║");
        Console.WriteLine("╚═══════════════════════════════════════╝");
        Console.WriteLine();

        while (!stoppingToken.IsCancellationRequested)
        {
            Console.Write("Research topic: ");
            var topic = Console.ReadLine();

            if (string.IsNullOrWhiteSpace(topic)
                || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
            {
                break;
            }

            try
            {
                await RunResearchAsync(topic, stoppingToken);
            }
            catch (Exception ex) when (ex is not OperationCanceledException)
            {
                _logger.LogError(ex, "Research failed");
                Console.WriteLine($"\nError: {ex.Message}");
            }

            Console.WriteLine();
        }

        _lifetime.StopApplication();
    }

    private async Task RunResearchAsync(string topic, CancellationToken ct)
    {
        Console.WriteLine($"\n🔍 Researching: {topic}\n");

        var tools = AIFunctionFactory.Create(_tools);

        var agent = _chatClient.AsAIAgent(
            instructions: AgentInstructions,
            name: "ResearchAgent",
            description: "An agent that researches topics by searching the web and taking notes.",
            tools: tools);

        var session = await agent.CreateSessionAsync(ct);
        var prompt = $"Research the following topic and provide a comprehensive summary: {topic}";

        Console.WriteLine("⏳ Agent is working...\n");

        await foreach (var update in agent.RunStreamingAsync(prompt, session, cancellationToken: ct))
        {
            if (update.Role == ChatRole.Assistant && !string.IsNullOrEmpty(update.Text))
            {
                Console.Write(update.Text);
            }
        }

        Console.WriteLine("\n");

        var notes = _notepad.GetNotes();
        if (notes.Count > 0)
        {
            Console.WriteLine($"📝 {notes.Count} research note(s) were recorded during this session.");
        }
    }
}

